def mirror_window(
    source_rows: dict[str, list[dict]],
    sink_rows: dict[str, list[dict]],
    symbol: str,
) -> int:
    """Copy one symbol window into the replay sink and return its row count."""
    rows = list(sink_rows.get(symbol, []))
    sink_rows[symbol] = rows
    return len(rows)

